package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.util.Arrays;

class CSVFormatEqualsTest {

    private CSVFormat createCSVFormat(char delimiter,
                                      QuoteMode quoteMode,
                                      Character quoteCharacter,
                                      Character commentMarker,
                                      Character escapeCharacter,
                                      String nullString,
                                      String[] header,
                                      boolean ignoreSurroundingSpaces,
                                      boolean ignoreEmptyLines,
                                      boolean skipHeaderRecord,
                                      String recordSeparator) throws Exception {
        // Use reflection to invoke private constructor
        return new CSVFormat(
                delimiter,
                quoteCharacter,
                quoteMode,
                commentMarker,
                escapeCharacter,
                ignoreSurroundingSpaces,
                ignoreEmptyLines,
                recordSeparator,
                nullString,
                null,
                header,
                skipHeaderRecord,
                false,
                false,
                false,
                false,
                false,
                false
        );
    }

    @Test
    void testEquals_sameObject() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertTrue(format.equals(format));
    }

    @Test
    void testEquals_nullObject() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.equals(null));
    }

    @Test
    void testEquals_differentClass() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.equals("a string"));
    }

    @Test
    void testEquals_differentDelimiter() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat('|', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_differentQuoteMode() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.MINIMAL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_quoteCharacterNullVsNonNull() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, null, '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));

        CSVFormat format3 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, null, '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format4 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, null, '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertTrue(format3.equals(format4));
    }

    @Test
    void testEquals_quoteCharacterEquals() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }

    @Test
    void testEquals_commentMarkerNullVsNonNull() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', null, '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));

        CSVFormat format3 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', null, '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format4 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', null, '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertTrue(format3.equals(format4));
    }

    @Test
    void testEquals_commentMarkerEquals() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }

    @Test
    void testEquals_escapeCharacterNullVsNonNull() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', null, null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));

        CSVFormat format3 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', null, null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format4 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', null, null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertTrue(format3.equals(format4));
    }

    @Test
    void testEquals_escapeCharacterEquals() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }

    @Test
    void testEquals_nullStringNullVsNonNull() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\", "null",
                new String[]{"a"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));

        CSVFormat format3 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format4 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', null,
                new String[]{"a"}, false, true, false, "\r\n");
        assertTrue(format3.equals(format4));
    }

    @Test
    void testEquals_nullStringEquals() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }

    @Test
    void testEquals_headerDifferent() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a", "c"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_headerEquals() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a", "b"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a", "b"}, false, true, false, "\r\n");
        assertTrue(format1.equals(format2));
    }

    @Test
    void testEquals_ignoreSurroundingSpaces() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, true, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_ignoreEmptyLines() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, false, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_skipHeaderRecord() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, true, "\r\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));
    }

    @Test
    void testEquals_recordSeparatorNullVsNonNull() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, null);
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, "\r\n");
        assertFalse(format1.equals(format2));

        CSVFormat format3 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, null);
        CSVFormat format4 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, null);
        assertTrue(format3.equals(format4));
    }

    @Test
    void testEquals_recordSeparatorEquals() throws Exception {
        CSVFormat format1 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, "\n");
        CSVFormat format2 = createCSVFormat(',', QuoteMode.ALL_NON_NULL, '"', '#', '\\', "null",
                new String[]{"a"}, false, true, false, "\n");
        assertTrue(format1.equals(format2));
    }
}
